class Product:
    def __init__(self, name, price, in_stock=True):
        self.name = name
        self.price = price
        self.in_stock = in_stock

def deposit(self, amount):
    self.balance += amount

def get_balance(self):
    return self.balance

def withdraw(self, amount):
    if amount > self.balance:
        print("Insufficient funds.")
        return
    self.balance -= amount

